function countPairsLess(a, target) {
  let lo = 0, hi = a.length - 1, count = 0;
  while (lo < hi) {
    if (a[lo] + a[hi] < target) { count += hi - lo; lo++; }
    else hi--;
  }
  return count;
}

function isPalAlnum(s) {
  const alnum = c => /[a-z0-9]/i.test(c);
  let lo = 0, hi = s.length - 1;
  while (lo < hi) {
    while (lo < hi && !alnum(s[lo])) lo++;
    while (lo < hi && !alnum(s[hi])) hi--;
    if (s[lo].toLowerCase() !== s[hi].toLowerCase()) return false;
    lo++;
    hi--;
  }
  return true;
}

function reverseVowels(s) {
  const vowels = new Set('aeiouAEIOU');
  const a = s.split('');
  let lo = 0, hi = a.length - 1;
  while (lo < hi) {
    if (!vowels.has(a[lo])) lo++;
    else if (!vowels.has(a[hi])) hi--;
    else { [a[lo], a[hi]] = [a[hi], a[lo]]; lo++; hi--; }
  }
  return a.join('');
}

