function partitionSign(a) {
  let lo = 0, hi = a.length - 1;
  while (lo < hi) {
    if (a[lo] < 0) lo++;
    else if (a[hi] >= 0) hi--;
    else { [a[lo], a[hi]] = [a[hi], a[lo]]; lo++; hi--; }
  }
  return a;
}

