function removeDupesTwo(a) {
  if (a.length <= 2) return a.length;
  let w = 2;
  for (let r = 2; r < a.length; r++) {
    if (a[r] !== a[w - 2]) { a[w] = a[r]; w++; }
  }
  return w;
}

