function sortColors(a) {
  let lo = 0, mid = 0, hi = a.length - 1;
  while (mid <= hi) {
    if (a[mid] === 0) { [a[lo], a[mid]] = [a[mid], a[lo]]; lo++; mid++; }
    else if (a[mid] === 2) { [a[mid], a[hi]] = [a[hi], a[mid]]; hi--; }
    else mid++;
  }
  return a;
}

function trap(h) {
  let lo = 0, hi = h.length - 1;
  let leftMax = 0, rightMax = 0, water = 0;
  while (lo < hi) {
    if (h[lo] < h[hi]) {
      leftMax = Math.max(leftMax, h[lo]);
      water += leftMax - h[lo];
      lo++;
    } else {
      rightMax = Math.max(rightMax, h[hi]);
      water += rightMax - h[hi];
      hi--;
    }
  }
  return water;
}

