solution:
function removeNth(nxt, start, n) {
  let fast = start;
  for (let i = 0; i < n; i++) fast = nxt[fast];
  if (fast === -1) return nxt[start];
  let slow = start;
  while (nxt[fast] !== -1) { fast = nxt[fast]; slow = nxt[slow]; }
  nxt[slow] = nxt[nxt[slow]];
  return start;
}

